using Odin.Api.Data.Enums;

namespace Odin.Api.Endpoints.AncestralPortraitManagement;

/// <summary>
/// Built-in, GENDER-SPECIFIC "ancestral self" scenes for each seeded qpAdm population — the period-accurate dress,
/// adornments and full-bleed cultural background the user is reimagined into for the paid "Through the Ages" add-on.
/// Keyed by the population's exact <see cref="Data.Entities.QpadmPopulation.Name"/>; each entry carries a MALE and a
/// FEMALE variant. The women's attire is independently period-researched (documented garments, headwear, hairstyle
/// and jewellery for that culture) — NOT a recoloured men's outfit, and women are not placed in men's armour unless
/// the culture attests it. <see cref="AncestralPortraitPrompts"/> uses these as the curated creative whenever a
/// population has no admin-set <c>QpadmPopulation.ImagePrompt</c> override (that override still wins), so the portrait
/// resembles the population's own photo instead of the bare name+description fallback. These are intentionally
/// distinct from the male-only avatar scenes in the FE manifest <c>POPULATION_IMAGE_PROMPTS</c>, which drive the
/// population AVATARS (always a man), not these identity-preserving, gendered user portraits.
/// </summary>
internal static class AncestralPortraitScenes
{
    /// <summary>
    /// When <paramref name="populationName"/> has a built-in scene, sets <paramref name="scene"/> to the
    /// gender-appropriate variant and returns true. Female → the women's variant; Male or null → the men's variant.
    /// </summary>
    public static bool TryGetScene(string? populationName, Gender? gender, out string scene)
    {
        if (populationName is not null && Scenes.TryGetValue(populationName.Trim(), out var variants))
        {
            scene = gender == Gender.Female ? variants.Female : variants.Male;
            return true;
        }

        scene = string.Empty;
        return false;
    }

    /// <summary>Population name → (men's scene, women's scene). Names match Data/SeedData/qpadm-populations.json.</summary>
    private static readonly IReadOnlyDictionary<string, (string Male, string Female)> Scenes =
        new Dictionary<string, (string Male, string Female)>(StringComparer.OrdinalIgnoreCase)
        {
            ["Anatolian Neolithic Farmer (8500 - 6000 BC)"] = (
                "A man of central Anatolia in the time of the first farmers (c. 8500-6000 BCE), wearing simple hand-woven garments of wool and tree-bast fibre in plain tabby weave, with a few bone and clay ornaments and pierced-stone beads. The full-bleed background is the world of the earliest agriculturalists: clustered mud-brick houses entered by rooftop ladders in the Çatalhöyük manner, plastered interior walls painted with aurochs and leaping bull motifs, sheaves of einkorn wheat and barley, a hafted flint sickle and a stone grinding quern, domesticated sheep and goats, hand-built painted pottery and a seated clay figurine, glossy obsidian blades, with the Anatolian plateau and distant volcanic cones beyond.",
                "A woman of central Anatolia in the time of the first farmers (c. 8500-6000 BCE), in a hand-woven wool-and-tree-bast garment of plain tabby weave: a spotted leopard-motif top and a wrapped fringed skirt after the Çatalhöyük figurines, her skin patterned with red ochre, adorned with strings of stone, shell, bone and clay beads, carved pendants and a bracelet, hair gathered. The full-bleed background is the first farmers' world: clustered mud-brick houses entered by rooftop ladders in the Çatalhöyük manner, plastered walls painted with aurochs and leaping bulls, sheaves of einkorn wheat and barley, a hafted flint sickle and stone grinding quern, sheep and goats, painted pottery and a seated clay figurine, glossy obsidian blades, and the Anatolian plateau with distant volcanic cones beyond."),
            ["Western Steppe Herder (5000 - 2800 BC)"] = (
                "A man of the Western Steppe Herders of the Pontic-Caspian steppe (Yamnaya culture, c. 3300-2600 BCE), a tall, robust adult, his hair tied back and his skin dusted with red ochre, wearing wool-and-leather garments under a heavy sheepskin cloak with a few bone and copper ornaments. The full-bleed background is the herder's world: rolling open grassland under a vast sky, a herd of cattle and shaggy horses, a heavy four-wheeled ox-drawn wooden wagon, a grassy kurgan burial mound on the horizon, corded-ware pottery, a copper axe, and hide tents beside a smouldering campfire.",
                "A woman of the Western Steppe Herders of the Pontic-Caspian steppe (Yamnaya culture, c. 3300-2600 BCE), a high-status adult, her skin dusted with red ochre and her hair bound back, in an undyed wool-and-hide gown edged with strands of bone, shell and stone beads and deer-tooth and boar-tusk pendants sewn along the hems, a copper-bead necklace, carved bone hammer-shaped pins at her shoulders and copper temple-ring ornaments by her brow. The full-bleed background is the herder's world: rolling open grassland under a vast sky, a herd of cattle and shaggy horses, a heavy four-wheeled ox-drawn wooden wagon, a grassy kurgan burial mound on the horizon, corded-ware pottery, a copper axe, and hide tents beside a smouldering campfire."),
            ["Western Hunter Gatherer (12000 - 6000 BC)"] = (
                "A man of Mesolithic Europe (c. 12,000-6,000 BCE), lean and weathered, his face marked with red ochre, wearing stitched animal-hide garments and strung necklaces of pierced shells, red-deer canine teeth and amber. The full-bleed background is the forager's world: dense temperate forest beside a still lake, a hunted red deer and a wild boar, a bow with flint-tipped arrows and a barbed antler harpoon, scattered microlith blades, a dugout canoe drawn up at the water's edge, and a hide shelter beside a smouldering fire.",
                "A woman of Mesolithic Europe (c. 12,000-6,000 BCE), lean and weathered, her face marked with red ochre, wearing a wrapped, stitched soft-hide dress with a fringed hem and a beaded hide cap and headband; rows of perforated Columbella and Glycymeris shells and red-deer canine teeth are sewn onto her bodice, sleeves and a hide belt, and amber pendants and elk-tooth strands hang at her throat. The full-bleed background is the forager's world: dense temperate forest beside a still lake, a hunted red deer and a wild boar, a bow with flint-tipped arrows and a barbed antler harpoon, scattered microlith blades, a dugout canoe drawn up at the water's edge, and a hide shelter beside a smouldering fire."),
            ["Eastern Hunter Gatherer (12000 - 5000 BC)"] = (
                "A man of the Mesolithic forest-steppe (c. 12,000-5,000 BCE, Lake Onega and the Volga-Urals), in thick layered fur and stitched hide garments with a fur-trimmed hood, strung with bone beads and rows of elk-tooth pendants, a smear of red ochre across his brow. The full-bleed background is the taiga forager's world: pine-and-birch forest meeting open rolling steppe, a great cold northern lake, a hunted elk and reindeer, a bone-tipped spear and a barbed antler harpoon, slate and antler tools, a dugout canoe drawn up at the shore, fishing nets hung to dry on wooden frames, and a fur-covered shelter beside a low fire.",
                "A woman of the Mesolithic forest-steppe (c. 12,000-5,000 BCE, Lake Onega and the Volga-Urals), in a long stitched hide-and-fur dress and fur-trimmed cloak whose hem, breast and belt are densely sewn with hundreds of rattling Eurasian elk-incisor pendants, a fur-and-hide headdress fringed with the same teeth and bone beads, strands of amber and shell beads at her throat, red ochre dusting her brow. The full-bleed background is the taiga forager's world: pine-and-birch forest meeting open rolling steppe, a great cold northern lake, an elk and grazing reindeer, a bone-tipped spear and barbed antler harpoon, slate and antler tools, a dugout canoe at the shore, fishing nets drying on wooden frames, and a fur-covered shelter beside a low fire."),
            ["Caucasian Hunter Gatherer (13000 - 7000 BC)"] = (
                "A man of the southern Caucasus foragers (c. 13,000-7,000 BCE, the Satsurblia and Kotias caves of Georgia), an adult hunter with long hair and a full beard, wearing stitched animal hides and woven plant-fibre wraps belted at the waist, strung with pendants of perforated animal teeth and bone and a few shell beads. The full-bleed background is the mountain forager's world: steep wooded Caucasus slopes and a dark cave mouth, a hunted wild tur (mountain goat) and a red deer, flint and obsidian blades, bone awls and a hafted spear, coils of twisted flax cordage, and a hearth glowing inside the rock shelter.",
                "A woman of the southern Caucasus foragers (c. 13,000-7,000 BCE, the Satsurblia and Kotias caves of Georgia), an adult of the band with her hair plaited back, wearing a wrapped dress of woven flax dyed in muted plant colours (ochre-red, yellow, brown) over softened hides, bound with twisted flax cordage, and adorned with strings of perforated red-deer teeth, polished bone and shell pendants at neck and brow. The full-bleed background is the mountain forager's world: steep wooded Caucasus slopes and a dark cave mouth, a hunted wild tur (mountain goat) and a red deer, flint and obsidian blades, bone awls and a hafted spear, coils of twisted flax cordage, and a hearth glowing inside the rock shelter."),
            ["Iranian Neolithic Farmer (8000 - 5000 BC)"] = (
                "A man of the Zagros highland farmers (c. 8000-5000 BCE, Ganj Dareh) wearing undyed homespun wool and goat-hair garments, plainly cut and belted, with simple bone ornaments and a few strung shell-and-stone beads at the throat. The full-bleed background is the highland farmer's world: terraced mud-brick dwellings clustered in a Zagros valley, a herd of newly domesticated goats, sheaves of barley and emmer wheat, a stone grinding quern and plastered storage bins, small clay counting tokens, coarse hand-formed pottery, and rugged mountain ridges beyond.",
                "A woman of the Zagros highland farmers (c. 8000-5000 BCE, Ganj Dareh) wearing an undyed homespun wool and goat-hair wrap, plain plain-weave cloth draped and belted at the waist, a simple woven headcloth over plaited bound hair, and her only ornaments strands of imported sea-shell and polished stone beads with a single drilled stone pendant - the modest adornment of an egalitarian village with no rank or finery. The full-bleed background is the highland farmer's world: terraced mud-brick dwellings clustered in a Zagros valley, a herd of newly domesticated goats, sheaves of barley and emmer wheat, a stone grinding quern and plastered storage bins, small clay counting tokens, coarse hand-formed pottery, and rugged mountain ridges beyond."),
            ["Natufian (12000 - 8000 BC)"] = (
                "A man of the Epipaleolithic Levant (c. 12,000-8,000 BCE), one of the first sedentary foragers, wearing a fitted hide garment and a headband and headdress sewn with rows of dentalium tusk-shells, with layered necklaces of dentalium beads, bone pendants and fox-teeth across his chest. The full-bleed background is the Natufian world: round semi-subterranean stone-walled houses roofed with brush, wild stands of einkorn and barley with a hafted flint sickle, deep stone mortars and pestles, bone fish-hooks and shell beads, a hunted gazelle at the field edge, a domesticated dog resting at his side, and the dry rolling Levantine hills beyond.",
                "A woman of the Epipaleolithic Levant (c. 12,000-8,000 BCE), one of the first sedentary foragers, wearing a soft hide garment and an elaborate close-fitting cap and headdress densely sewn with rows of dentalium tusk-shells, a broad pectoral cluster of dentalium beads, bird-bone tube beads and tusk-shell spacers across her chest, strung pendants of carved gazelle phalanx bones, and a girdle of dentalium shells at her waist. The full-bleed background is the Natufian world: round semi-subterranean stone-walled houses roofed with brush, wild stands of einkorn and barley with a hafted flint sickle, deep stone mortars and pestles, bone fish-hooks and shell beads, a hunted gazelle at the field edge, a domesticated dog resting nearby, and the dry rolling Levantine hills beyond."),
            ["North African Farmer (5200 - 4000 BC)"] = (
                "A man of the North African Neolithic Maghreb (c. 5200-4000 BCE), an adult male farmer-herder in a wrapped tunic of woven wool and softened hide, belted at the waist, with a hide mantle over one shoulder; he wears strands of ostrich-eggshell disc beads and pierced marine-shell ornaments at his neck, bone pendants, and a faint dusting of red ochre on his brow. The full-bleed background is the Maghreb farmer's world filling the frame edge to edge: a coastal cave camp sheltered below the Atlas foothills, mingled herds of sheep, goats and cattle, impressed Cardial-ware pottery, hafted flint sickles and flat grinding stones, loose sheaves of harvested grain, drying skins, and the Mediterranean shore meeting dry sun-baked hills under a bright sky.",
                "A woman of the North African Neolithic Maghreb (c. 5200-4000 BCE), an adult female farmer-herder in a wrapped, draped dress of woven wool and softened hide pinned at one shoulder and gathered with a woven belt, a hide shawl across her back; her hair is in fine Maghrebi braids bound with bone pins, and she wears ostrich-eggshell disc beads, cowrie and Nassarius shell necklaces, and red ochre on her brow. The full-bleed background is the Maghreb farmer's world filling the frame edge to edge: a coastal cave camp sheltered below the Atlas foothills, mingled herds of sheep, goats and cattle, impressed Cardial-ware pottery, hafted flint sickles and flat grinding stones, loose sheaves of harvested grain, drying skins, and the Mediterranean shore meeting dry sun-baked hills under a bright sky."),
            ["Northeast Asian (6000 - 2000 BC)"] = (
                "A man of Holocene Siberia (c. 6000-2000 BCE, the Altai and Trans-Baikal) — a hunter wearing a thick tailored fur parka with a fur-lined hood and hide boots, strung with bone and antler ornaments and pierced animal-tooth pendants. The full-bleed background is the Siberian world: snow-dusted taiga forest meeting open tundra under a pale cold sky, a grazing reindeer herd and a hunted elk, a composite bow and a bone-tipped harpoon leaning as scenery, a lashed wooden sledge, fish drying on wooden racks, a conical skin tent with its flap lifting, and a shaman's antler talisman by a low fire.",
                "A woman of Holocene Siberia (c. 6000-2000 BCE, the Altai and Trans-Baikal) — of elite standing in a tailored fur and hide garment with a fur-lined hood, richly adorned in the manner of the Cis-Baikal Neolithic dead: layered collars and strands of polished bone and antler tubular beads, pierced animal-tooth and shell pendants, and a bead-sewn hide bodice. The full-bleed background is the Siberian world: snow-dusted taiga forest meeting open tundra under a pale cold sky, a grazing reindeer herd and a hunted elk, a composite bow and a bone-tipped harpoon leaning as scenery, a lashed wooden sledge, fish drying on wooden racks, a conical skin tent with its flap lifting, and a shaman's antler talisman by a low fire."),
            ["Native American (15000 - 1500 BC)"] = (
                "A man of the late Pleistocene–Archaic Americas (c. 15,000–1500 BCE), descended from the first Beringian founders, his long straight hair worn loose and his face touched with ochre, wearing fringed soft-tanned hide garments with a hide cloak and ornaments of bone, shell and eagle feather, a beaded necklace of pierced shell and animal teeth. The full-bleed background is the First Americans' world: a vast wild landscape of open plains, woodland and distant snow-capped peaks, a herd of hunted bison and caribou drifting across the grass, an atlatl spear-thrower with fluted stone points leaning ready, conical hide tents, a campfire with strips of meat drying on wooden racks, and migratory game moving along the far horizon under a wide open sky.",
                "A woman of the late Pleistocene–Archaic Americas (c. 15,000–1500 BCE), descended from the first Beringian founders, her long straight hair worn in plaits and her brow touched with ochre, wearing a fringed soft-tanned hide dress sewn with bone needle, a twined plant-fibre apron and woven sandals, a hide robe about her shoulders, and ornaments of bone, shell, seed beads and porcupine quillwork. The full-bleed background is the First Americans' world: a vast wild landscape of open plains, woodland and distant snow-capped peaks, a herd of bison and caribou drifting across the grass, an atlatl spear-thrower with fluted stone points by the camp, conical hide tents, a campfire with meat drying on wooden racks, and migratory game along the far horizon under a wide open sky."),
            ["Ancestral South Indian (10000 - 2000 BC)"] = (
